                "token": "time_range"
            },
            "title": "Time Range Input Title",
            "type": "input.timerange"
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {}
                }
            }
        }
    },
    "visualizations": {
        "viz_T3PdOwag": {
            "dataSources": {
                "primary": "ds_gNPaEDDs"
            },
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row.HostName.value",
                                "token": "clicked_server"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "title": "Active CPU Utilization",
            "type": "splunk.table"
        },
        "viz_asKJrUc8": {
            "context": {
                "Slots_with_ServersColumnColorConfig": {
                    "colors": [
                        "#FFFFFF",
                        "#118832"
                    ]
                },
                "Slots_with_ServersColumnTextColorConfig": {
                    "colors": [
                        "#000000",
                        "#FFFFFF"
                    ]
                },
                "Total_Unused_Server_SlotsColumnColorConfig": {
                    "colors": [
                        "#FFFFFF",
                        "#D41F1F"
                    ]
                },
                "Total_Unused_Server_SlotsColumnTextColorConfig": {
                    "colors": [
                        "#000000",
                        "#FFFFFF"
                    ]
                },
                "Unused_Server_SlotColumnColorConfig": [
                    {
                        "to": 2,
                        "value": "#118832"
                    },
                    {
                        "from": 2,
                        "to": 4,
                        "value": "#CBA700"
                    },
                    {
                        "from": 4,
                        "to": 6,
                        "value": "#D94E17"
                    },
                    {
                        "from": 6,
                        "to": 7,
                        "value": "#9E2520"
                    },
                    {
                        "from": 7,
                        "value": "#3C444D"
                    }
                ],
                "empty_slot_countColumnColorConfig": [
                    {
                        "to": 1,
                        "value": "#118832"
                    },
                    {
                        "from": 1,
                        "to": 3,
                        "value": "#1182F3"
                    },
                    {
                        "from": 3,
                        "to": 5,
                        "value": "#CBA700"
                    },
                    {
                        "from": 5,
                        "to": 7,
                        "value": "#D94E17"
                    },
                    {
                        "from": 7,
                        "value": "#D41F1F"
                    }
                ]
            },
            "dataSources": {
                "primary": "ds_V1IgnA1c"
            },
            "options": {
                "columnFormat": {
                    "Slots with Servers": {
                        "rowBackgroundColors": "> table | seriesByName(\"Slots with Servers\") | gradient(Slots_with_ServersColumnColorConfig)",
                        "rowColors": "> table | seriesByName(\"Slots with Servers\") | gradient(Slots_with_ServersColumnTextColorConfig)"
                    },
                    "Total Unused Server Slots": {
                        "rowBackgroundColors": "> table | seriesByName(\"Total Unused Server Slots\") | gradient(Total_Unused_Server_SlotsColumnColorConfig)",
                        "rowColors": "> table | seriesByName(\"Total Unused Server Slots\") | gradient(Total_Unused_Server_SlotsColumnTextColorConfig)"
                    },
                    "Unused Server Slot": {
                        "rowBackgroundColors": "> table | seriesByName(\"Unused Server Slot\") | rangeValue(Unused_Server_SlotColumnColorConfig)"
                    },
                    "empty_slot_count": {
                        "rowBackgroundColors": "> table | seriesByName(\"empty_slot_count\") | rangeValue(empty_slot_countColumnColorConfig)"
                    }
                },
                "drilldown": "none",
                "showInternalFields": false
            },
            "title": "Unused Server Slots",
            "type": "splunk.table"
        },
        "viz_uDbzYYs3": {
            "dataSources": {
                "primary": "ds_oyL23IwK"
            },
            "options": {
                "legendDisplay": "top",
                "legendTruncation": "ellipsisMiddle"
            },
            "showLastUpdated": false,
            "showProgressBar": false,
            "title": "Physical CPU Utilization - Server: ($clicked_server$)",
            "type": "splunk.line",
            "hideWhenNoData": true
        }
    },
    "dataSources": {
        "ds_AG0DqAd3": {
            "name": "Domains search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count from datamodel=Cisco_Intersight where nodename=cisco_intersight.cisco_intersight_cpu_utilization \n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_account_name IN ($cpu_util_account$)\n    by cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_name, cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_id\n| rename cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_name as DomainName, cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_id as DomainId\n| table DomainName, DomainId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_EGaM7dXo": {
            "name": "Unused Server Slots Account Name",
            "options": {
                "query": "| inputlookup cisco_intersight_equipment_chasses | where splunk_managed_lifecycle == \"PRESENT\"\n| dedup account_name\n| table account_name",
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                }
            },
            "type": "ds.search"
        },
        "ds_V1IgnA1c": {
            "name": "Unused Server Slots - Table search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_bladeidentities\n| where splunk_managed_lifecycle==\"PRESENT\"\n| search account_name IN ($unused_server_slots_account_name$)\n| rename CurrentChassisId as ChassisId\n| rename RegisteredDevice.Moid as DeviceMoId\n|  search DeviceMoId=\"$deviceids$\"\n| eval DeviceMoId_ChassisId = DeviceMoId . \"_\" . ChassisId\n| eval DeviceMoId_ChassisId_slot = DeviceMoId_ChassisId . \"_\" . CurrentSlotId\n| dedup DeviceMoId_ChassisId_slot\n| sort CurrentSlotId\n| eval used_slots = if(isnotnull(CurrentSlotId), CurrentSlotId, \"null\")\n| stats list(used_slots) as used_slots by DeviceMoId, ChassisId, RegisteredDevice.DeviceHostname, DeviceMoId_ChassisId\n| eval used_slots_count = mvcount(used_slots)\n\n| join type=left DeviceMoId_ChassisId \n    [ | inputlookup cisco_intersight_equipment_chasses\n      | where splunk_managed_lifecycle==\"PRESENT\"\n      | rename RegisteredDevice.Moid as DeviceMoId, Model as ChassesModel\n      | eval DeviceMoId_ChassisId = DeviceMoId . \"_\" . ChassisId\n      | table DeviceMoId_ChassisId, PlatformType, Name, ChassesModel\n    ]\n\n| eval total_slots_available = if(match(ChassesModel, \"^UCSXE\"), 5, 8)\n| eval empty_slot_count = total_slots_available - used_slots_count\n| eval Slots_in_Use = mvjoin(used_slots, \", \")\n| rename RegisteredDevice.DeviceHostname as DeviceHostname\n| where isnotnull(DeviceHostname)\n| sort 0 -empty_slot_count\n| rename DeviceMoId as \"Device Id\",\n         DeviceHostname as \"Intersight Domain\",\n         Name as \"Chassis Name\",\n         empty_slot_count as \"Total Unused Server Slots\",\n         used_slots_count as \"Slots with Servers\",\n         Slots_in_Use as \"IDs of Slots Connected to Server\"\n\n| eval Type = if(match(ChassesModel, \"^UCSXE\"), \"Unified Edge\", \"IMM\")\n| table \"Intersight Domain\", \"Chassis Name\", Type, \"Total Unused Server Slots\", \"Slots with Servers\", \"IDs of Slots Connected to Server\"",
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                }
            },
            "type": "ds.search"
        },
        "ds_WwUvuTPo": {
            "name": "Account search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` \n    values(cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_account_name) as account_name \n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_cpu_utilization \n| mvexpand account_name",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_aXnHZlAJ": {
            "name": "Intersight Domains 2 search",
            "options": {
                "query": "| inputlookup cisco_intersight_compute_bladeidentities | where splunk_managed_lifecycle == \"PRESENT\"\n      | search account_name IN ($unused_server_slots_account_name$)\n      | dedup RegisteredDevice.Moid\n      | rename RegisteredDevice.Moid as DeviceMoId \n      | rename RegisteredDevice.DeviceHostname as DeviceHostname \n      | where isnotnull(DeviceHostname) \n      | table DeviceMoId, DeviceHostname ",
                "queryParameters": {
                    "earliest": "-24h@h",
                    "latest": "now"
                }
            },
            "type": "ds.search"
        },
        "ds_e7d8BYrx": {
            "name": "Server search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count \n    from datamodel=Cisco_Intersight\n    where nodename=cisco_intersight.cisco_intersight_cpu_utilization \n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_id IN ($cpu_util_domain$)\n        AND (\n            cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_chassis_moid IN ($cpu_util_chassis$)\n            OR NOT cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_chassis_moid=*\n        )\n    by cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name, \n       cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_id\n| rename cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name as HostName,\n         cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_id as HostId\n| dedup HostId\n| table HostName, HostId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_gNPaEDDs": {
            "name": "Physical CPU Utilization - Table search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n    values(cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_max) as cpu_util_max\n    values(cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_average) as cpu_util_avg\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_cpu_utilization \n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_account_name IN ($cpu_util_account$)\n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_id IN ($cpu_util_domain$)\n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_chassis_moid IN ($cpu_util_chassis$)\n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_id IN ($cpu_util_server$)\n    by _time, cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name, cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_id\n    span=1m\n\n| eval server_moid_link = 'cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_id'\n| eval server_moid = mvindex(split('server_moid_link', \"/\"), -1)\n| join type=left server_moid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename OperPowerState as power_status, Moid as server_moid | table server_moid, power_status ]\n\n| where \"$show_powered_off$\"=\"true\" OR lower(coalesce(power_status, \"\"))=\"on\"\n| rename cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name as HostName\n| eval cpu_util_max=cpu_util_max*100, cpu_util_avg=cpu_util_avg*100\n| stats sparkline(avg(cpu_util_avg)) as \"Avg CPU Trend (%)\", sparkline(avg(cpu_util_max)) as \"Max CPU Trend (%)\" by HostName\n| table HostName, \"Avg CPU Trend (%)\", \"Max CPU Trend (%)\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_oyL23IwK": {
            "name": "Physical CPU Utilization - Server - Line chart search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n    values(cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_max) as cpu_util_max\n    values(cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_average) as cpu_util_avg\n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_cpu_utilization \n        AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name=$clicked_server$\n    by _time, cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name\n    span=1m\n| rename cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_server_name as HostName\n| eval cpu_util_max=round(cpu_util_max*100, 2)\n| eval cpu_util_avg=round(cpu_util_avg*100, 2)\n| timechart span=15m values(cpu_util_avg) as \"Active CPU Utilization-Average\", values(cpu_util_max) as \"Active CPU Utilization-Maximum\" by HostName",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_p1rI293p": {
            "name": "Chassis search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n    from datamodel=Cisco_Intersight\n    where nodename=cisco_intersight.cisco_intersight_cpu_utilization AND cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_domain_id IN ($cpu_util_domain$)\n    by cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_chassis_moid\n| rename cisco_intersight.cisco_intersight_cpu_utilization.cpu_util_chassis_moid as ChassisMoid\n| join type=left ChassisMoid \n[ | inputlookup cisco_intersight_equipment_chasses | where splunk_managed_lifecycle == \"PRESENT\" | rename Name as ChassisName, Moid as ChassisMoid ]\n| search ChassisMoid!=null\n| dedup ChassisMoid\n| table ChassisMoid, ChassisName",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "type": "ds.search"
        }
    },
    "layout": {
        "type": "grid",
        "options": {
            "height": 3754,
            "width": 1440
        },
        "structure": [
